9	type Item = { type: string; material: string; enchantment: number; cursed: boolean };
10	
11	export function quote(input: { yearsWithMHPCO: number; items: Item[] }): number {
12	  const itemsBaseTotal = input.items.reduce(
13	    (sum, item) => sum + BASE_PREMIUM_BY_ITEM_TYPE[item.type],
14	    0
15	  );
16	  return itemsBaseTotal + PROCESSING_FEE;
17	}
